VALUES
  ('heelevel3-5ff21eeb-moex-00024', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列何者非為民法上之物權？', '["不動產役權", "典權", "權利質權", "遺產之使用收益權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00025', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於不動產所有權之取得或移轉，何者應辦理登記，始發生效力？', '["私人土地之徵收", "法院強制執行拍賣債務人名下之土地，而由他人拍定", "私人拋棄其土地所有權", "私人蓋好房屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00026', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲男乙女為夫妻，甲竟與乙之姪女丙發生姦情。乙訴請判決離婚，判決確定之一個月後，甲與丙 結婚。下列敘述，何者正確？', '["甲丙違反待婚期間之限制，其婚姻得撤銷", "甲丙違反相姦婚禁止之規定，其婚姻得撤銷", "甲丙違反近親結婚之限制，其婚姻無效", "甲丙並未違反規定，其婚姻有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00027', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '遺產分割後，其未清償之被繼承人之債務，移歸一定之人承受，或劃歸各繼承人分擔，如經債權 人同意者，各繼承人得免除何種責任？', '["連帶保證", "連帶責任", "連帶債權", "侵權責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00028', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00029', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00030', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00031', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00032', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'essay', '甲將其名下所有某公司之股票全部贈與其配偶乙。甲依法申報並經核定
免徵贈與稅。甲於半年後死亡。甲之配偶乙及其婚生子女丙均拋棄繼承，
甲之未成年非婚生子女丁成為甲遺產之唯一繼承人。稽徵機關認定上述
股票為被繼承人甲死亡前 2年內贈與配偶之財產，故依遺產及贈與稅法
第 15 條第 1 項第 1 款規定：「被繼承人死亡前 2年內贈與下列個人之財
產，應於被繼承人死亡時，視為被繼承人之遺產，併入其遺產總額，依
本法規定徵稅：一、被繼承人之配偶。」，將被繼承人死亡時之股票淨值
計入遺產總額，核定丁之應納稅額為 60,000,000元。其稅額實際上已經
超出丁因繼承所得之財產。請依據法理分析上開規定是否違憲。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00033', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'essay', '甲公司未經許可，販賣槍砲、彈藥而獲取高額不法暴利。請問稽徵機關
應否將其不法所得納入其所得課稅？若刑事法院已經先裁判沒收其犯
罪所得時，則稽徵機關得否仍將其不法所得納入其所得課稅？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
